<template><div class="page"><header class="page-head"><div><h1>Parametres</h1><p>Connexions principales et cadence de synchronisation.</p></div><a class="secondary" href="/settings">Configuration avancee</a></header><p v-if="error" class="notice error-text">{{ error }}</p><p v-if="saved" class="notice success-text">Configuration enregistree.</p><form class="settings-grid" @submit.prevent="save"><section class="panel form-section"><h2>Plex</h2><label>URL<input v-model="form.plex_url" type="url" placeholder="http://plex:32400"/></label><label>Token<input v-model="form.plex_token" type="password" placeholder="Laisser vide pour conserver"/></label><label class="check"><input v-model="form.plex_verify_ssl" type="checkbox"/> Verifier le certificat TLS</label></section><section class="panel form-section"><h2>Seer et TMDB</h2><label>URL Seer<input v-model="form.seer_url" type="url"/></label><label>Cle API Seer<input v-model="form.seer_api_key" type="password"/></label><label>Cle TMDB<input v-model="form.tmdb_api_key" type="password"/></label></section><section class="panel form-section"><h2>Automatisation</h2><label>Intervalle watchlist (secondes)<input v-model.number="form.poll_interval_seconds" type="number" min="15"/></label><label class="check"><input v-model="form.vff_enabled" type="checkbox"/> Analyse VF active</label><label class="check"><input v-model="form.require_approval" type="checkbox"/> Approbation admin requise</label></section><div class="form-actions"><button class="primary" :disabled="saving"><Save/>{{ saving?'Enregistrement...':'Enregistrer' }}</button></div></form></div></template>
<script setup>import { onMounted,reactive,ref } from "vue";import { Save } from "@lucide/vue";import { api } from "@/api";const form=reactive({plex_url:'',plex_token:'',plex_verify_ssl:true,seer_url:'',seer_api_key:'',tmdb_api_key:'',poll_interval_seconds:300,vff_enabled:true,require_approval:false}),saving=ref(false),error=ref(''),saved=ref(false);async function load(){try{const data=await api('/api/settings');for(const key of Object.keys(form)){if(data[key]!=null)form[key]=data[key]}form.plex_token='';form.seer_api_key='';form.tmdb_api_key=''}catch(e){error.value=e.message}}async function save(){saving.value=true;error.value='';saved.value=false;const payload={...form};for(const key of ['plex_token','seer_api_key','tmdb_api_key'])if(!payload[key])delete payload[key];try{await api('/api/settings',{method:'PUT',body:JSON.stringify(payload)});saved.value=true}catch(e){error.value=e.message}finally{saving.value=false}}onMounted(load);</script>
